// Extract business_id, range, metric from body or query
const body = $input.item.json.body || $input.item.json || {};
const query = $input.item.json.query || {};

const businessId = body.business_id || query.business_id || 'all';
const range = parseInt(body.range || query.range || 7);
const metric = body.metric || query.metric || 'revenue';

const now = new Date();

// Today
const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
const todayEnd = new Date(todayStart);
todayEnd.setDate(todayEnd.getDate() + 1);

// Range start (7, 30, or 90 days ago)
const rangeStart = new Date(now);
rangeStart.setDate(rangeStart.getDate() - range);
rangeStart.setHours(0, 0, 0, 0);

return {
  json: {
    business_id: businessId,
    range,
    metric,
    today_start: todayStart.toISOString(),
    today_end: todayEnd.toISOString(),
    today_date: now.toISOString().split('T')[0],
    range_start: rangeStart.toISOString(),
    range_end: now.toISOString()
  }
};

const bizData = $('Extract Business ID').item.json;
const range = bizData.range || 7;
const metric = bizData.metric || 'revenue';

const rangeOrders = $('Get Range Orders').all();
const lowStockData = $('Get Low Stock').all();
const recentOrdersData = $('Get Recent Orders').all();
const recentLeadsData = $('Get Recent Leads').all();

const now = new Date();
const todayStr = bizData.today_date;

// --- Today metrics ---
const todayOrders = rangeOrders.filter(o => {
  const d = o.json.date_created || '';
  return d.startsWith(todayStr);
});

let todayRevenue = 0;
let pendingOrders = 0;
const oneHourAgo = new Date(now - 3600000);

for (const order of todayOrders) {
  const status = (order.json.status || '').toLowerCase();
  if (!['cancelled', 'refunded', 'failed'].includes(status)) {
    todayRevenue += parseFloat(order.json.total) || 0;
  }
  if (status === 'processing') pendingOrders++;
}

const ordersLastHour = rangeOrders.filter(o => new Date(o.json.date_created) >= oneHourAgo).length;

// --- Build daily chart_data for the selected range ---
// Create a map of date -> {revenue, orders}
const dayMap = {};

// Initialize all days in range to 0
for (let i = range - 1; i >= 0; i--) {
  const d = new Date(now);
  d.setDate(d.getDate() - i);
  const key = d.toISOString().split('T')[0];
  dayMap[key] = { date: key, revenue: 0, orders: 0, leads: 0 };
}

// Fill orders data
for (const o of rangeOrders) {
  const status = (o.json.status || '').toLowerCase();
  const dateStr = (o.json.date_created || '').substring(0, 10);
  if (!dayMap[dateStr]) continue;

  if (!['cancelled', 'refunded', 'failed'].includes(status)) {
    dayMap[dateStr].revenue += parseFloat(o.json.total) || 0;
  }
  dayMap[dateStr].orders += 1;
}

// Fill leads data
for (const l of recentLeadsData) {
  const dateStr = (l.json.created_at || '').substring(0, 10);
  if (dayMap[dateStr]) dayMap[dateStr].leads += 1;
}

// Convert to sorted array with formatted labels
const chart_data = Object.values(dayMap)
  .sort((a, b) => a.date.localeCompare(b.date))
  .map(d => ({
    date: d.date,
    label: range <= 7
      ? new Date(d.date).toLocaleDateString('en-US', { weekday: 'short' })
      : range <= 31
        ? new Date(d.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
        : new Date(d.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
    revenue: Math.round(d.revenue),
    orders: d.orders,
    leads: d.leads
  }));

// --- Summary metrics ---
const totalRevenue = rangeOrders
  .filter(o => !['cancelled','refunded','failed'].includes((o.json.status||'').toLowerCase()))
  .reduce((s, o) => s + (parseFloat(o.json.total) || 0), 0);

const totalOrders = rangeOrders.length;
const avgOrderValue = totalOrders > 0 ? Math.round(totalRevenue / totalOrders) : 0;

// Status counts
const statusCounts = {};
rangeOrders.forEach(o => {
  const s = o.json.status || 'unknown';
  statusCounts[s] = (statusCounts[s] || 0) + 1;
});

// Low stock
const lowStockList = lowStockData.map(i => ({
  product_name: i.json.name,
  stock_quantity: i.json.stock_quantity,
  sku: i.json.sku
}));

// Recent orders
const recentOrdersList = recentOrdersData.map(o => {
  const createdAt = new Date(o.json.date_created);
  const diffMins = Math.floor((now - createdAt) / 60000);
  const timeAgo = diffMins < 1 ? 'Just now'
    : diffMins < 60 ? `${diffMins} mins ago`
    : `${Math.floor(diffMins/60)} hrs ago`;
  return {
    wc_order_id: o.json.wc_order_id,
    order_number: o.json.order_number,
    customer_name: o.json.customer_name,
    total: o.json.total,
    status: o.json.status,
    date_created: o.json.date_created,
    time_ago: timeAgo
  };
});

// Recent leads
const recentLeadsList = recentLeadsData.map(l => ({
  name: l.json.name,
  email: l.json.email,
  source: l.json.source,
  lead_score: l.json.lead_score,
  status: l.json.status,
  created_at: l.json.created_at
}));

return {
  json: {
    success: true,
    business_id: bizData.business_id,
    range,
    metric,
    generated_at: now.toISOString(),
    chart_data,
    dashboard: {
      metrics: {
        total_orders_today: todayOrders.length,
        orders_last_hour: ordersLastHour,
        revenue_today: Math.round(todayRevenue * 100) / 100,
        pending_orders: pendingOrders,
        low_stock_alerts: lowStockData.length,
        total_revenue_range: Math.round(totalRevenue),
        total_orders_range: totalOrders,
        avg_order_value: avgOrderValue,
        status_counts: statusCounts
      },
      recent_orders: recentOrdersList,
      low_stock_items: lowStockList,
      recent_leads: recentLeadsList
    },
    summary: {
      status: 'active',
      needs_attention: lowStockData.length > 0,
      last_updated: now.toISOString()
    }
  }
};
